mapper.insert:
MERGE INTO SENTENCE_USER T USING (
SELECT #{item.id} AS id, #{item.text} AS text, #{item.sentenceId} AS sentenceId, #{item.treeGroupId} AS treeGroupId, #{item.userId} AS userId FROM dual
) SRC ON (T.USER_ID = SRC.userId AND T.SENTENCE_ID = SRC.sentenceId) WHEN MATCHED THEN UPDATE SET T.TEXT = SRC.text, T.UPDATE_DT = SYSDATE WHEN NOT MATCHED THEN INSERT (ID, TEXT, TREE_GROUP_ID, SENTENCE_ID, USER_ID) VALUES (SENTENCE_USER_SEQ.NEXTVAL, SRC.text, SRC.treeGroupId, SRC.sentenceId, SRC.userId)
